const e=require("fs"),t=e.readFileSync("google_contacts_840.csv","utf8").split("\n"),n=t.filter(e=>{if(!e.trim())return!1;if(e.startsWith("Name"))return!0;const t=e.split(",");return!(t.length>1&&t[1].trim().startsWith("+86"))});e.writeFileSync("google_contacts_filtered.csv",n.join("\n")),console.log(`Original count: ${t.length-1} (including header)`),console.log("Filtered count: "+(n.length-1)),console.log(`Successfully removed ${t.length-n.length} China numbers (+86).`);